    use soroban_sdk::{Env};

    /// Property: the output of `clamp_value` must always satisfy
    ///   min <= result <= max
    /// for any (val, min, max) triple where min <= max.
    proptest! {
        #[test]
        fn prop_value_within_bounds(
            val in i64::MIN..=i64::MAX,
            min in 0i64..=500_000i64,
            max in 500_001i64..=1_000_000i64,
        ) {
            let env = Env::default();
            env.mock_all_auths();
            let contract_id = env.register(MyContract, ());
            let client = MyContractClient::new(&env, &contract_id);

            let result = client.clamp_value(&val, &min, &max);

            prop_assert!(
                result >= min && result <= max,
                "result {} must satisfy {} <= result <= {}",
                result, min, max
            );
        }
    }
