#[cfg(test)]
mod prop_tests {
    use super::*;
    use proptest::prelude::*;
    use soroban_sdk::{testutils::Address as _, Address, Env};

    /// Property: the balance of any account must never drop below zero,
    /// regardless of the sequence or size of withdraw calls.
    proptest! {
        #[test]
        fn prop_balance_never_negative(
            initial_deposit in 1i128..=100_000_000i128,
            withdraw_amount in 1i128..=100_000_000i128,
        ) {
            let env = Env::default();
            env.mock_all_auths();

            let user = Address::generate(&env);
            let contract_id = env.register(TokenContract, ());
            let client = TokenContractClient::new(&env, &contract_id);

            // Fund the account
            client.deposit(&user, &initial_deposit);

            // Attempt a withdrawal — may succeed or be rejected, but must
            // never leave the balance negative.
            let _ = client.try_withdraw(&user, &withdraw_amount);

            let balance = client.balance(&user);
            prop_assert!(
                balance >= 0i128,
                "balance must be non-negative after withdrawal, got {}",
                balance
            );
        }
    }
}

