mod prop_tests {
    use super::*;
    use proptest::prelude::*;
    use soroban_sdk::Env;

    /// DEMO: This test is intentionally broken.
    ///
    /// It asserts that the counter value is always <= 100, but the strategy
    /// generates values up to 1_000.  Proptest will find a failing case and
    /// then shrink it to the minimal counter-example: value = 101.
    ///
    /// Run this to see the ProptestView shrinking animation in action.
    /// Remove or fix the assertion once you are done exploring the UI.
    proptest! {
        #[test]
        fn prop_shrinking_demo(value in 0u32..=1_000u32) {
            let env = Env::default();
            let contract_id = env.register(IncrementContract, ());
            let client = IncrementContractClient::new(&env, &contract_id);

            // Advance the counter to `value`
            for _ in 0..value {
                client.increment();
            }

            let count = client.get_count();

            // ⚠️  Deliberately wrong bound — will fail for value > 100.
            // Proptest will shrink the failing input to exactly 101.
            prop_assert!(
                count <= 100,
                "expected count <= 100 but got {} (input value = {})",
                count, value
            );
        }
    }
}
